CODE_EXAMPLE:
class EventBus {
    private List<Event> events = new ArrayList<>();

    public void publish(Event e) { events.add(e); }

    public List<Event> getEvents() { return Collections.unmodifiableList(events); }
}

UNIT_TEST_EXAMPLE:
@Test
public void publish_addsEventToQueue() {
    EventBus bus = new EventBus();
    Event event = new Event("user.created");
    bus.publish(event);
    assertEquals(1, bus.getEvents().size());
    assertEquals(event, bus.getEvents().get(0));
}
